import React, { useEffect, useState } from "react";
import { getTrips } from "../api";

function TripTable() {

  const [trips, setTrips] = useState([]);

  useEffect(() => {
    getTrips().then(data => setTrips(data));
  }, []);

  return (
    <div>
      <h2>Trips</h2>

      {trips.map(trip => (
        <div key={trip.id}>
          {trip.id} | {trip.route_id} | {trip.train_id}
        </div>
      ))}

    </div>
  );
}

export default TripTable;
